(() => {
    const root = document.getElementById("while-stepper");
    if (!root) return;
    const steps = [{"title":"Initial value","text":"The variable must have a value before the condition can be checked.","code":"count = 0"},{"title":"Condition check","text":"Python checks whether the condition is True.","code":"while count < 5:"},{"title":"Indented block","text":"If the condition is True, Python runs the indented code.","code":"    print(count)\n    count += 1"},{"title":"Repeat or stop","text":"Python goes back to the condition. When count reaches 5, count < 5 is False and the loop stops.","code":"0, 1, 2, 3, 4"}];
    let i = 0;
    function render(){
      const s = steps[i];
      root.innerHTML = '<div class="ex-progress">Step ' + (i + 1) + ' of ' + steps.length + '</div><h3>' + s.title + '</h3><p>' + s.text + '</p><pre class="ex-code"><code>' + s.code + '</code></pre><button type="button" class="ex-btn" id="prev">Back</button> <button type="button" class="ex-btn" id="next">' + (i === steps.length - 1 ? 'Finish' : 'Next') + '</button>';
      root.querySelector('#prev').disabled = i === 0;
      root.querySelector('#prev').onclick = () => { if (i > 0) { i--; render(); } };
      root.querySelector('#next').onclick = () => {
        if (i < steps.length - 1) { i++; render(); }
        else if (window.__markStepComplete) window.__markStepComplete();
      };
    }
    render();
  })();

