(() => {
    const root = document.getElementById("inc-dec-practice-box");
    if (!root) return;
    const questions = [{"type":"text","q":"Write the code that increases score by 5.","pattern":"^\\s*score\\s*\\+=\\s*5\\s*$","right":"Correct.","wrong":"Use score += 5."},{"type":"text","q":"Write the code that decreases lives by 1.","pattern":"^\\s*lives\\s*-=\\s*1\\s*$","right":"Correct.","wrong":"Use lives -= 1."},{"type":"text","q":"Write the code that increases total by 10.","pattern":"^\\s*total\\s*\\+=\\s*10\\s*$","right":"Correct.","wrong":"Use total += 10."},{"type":"text","q":"Write the code that decreases health by 25.","pattern":"^\\s*health\\s*-=\\s*25\\s*$","right":"Correct.","wrong":"Use health -= 25."},{"type":"mcq","q":"Which statement increases count by 1?","options":["count += 1","count -= 1","count =+ 1","count + 1"],"answer":"count += 1","right":"Correct.","wrong":"+= updates the variable."},{"type":"text","q":"Write the code that decreases battery by 5.","pattern":"^\\s*battery\\s*-=\\s*5\\s*$","right":"Correct.","wrong":"Use battery -= 5."}];
    let idx = 0, score = 0;
    function complete(){
      root.innerHTML = '<div class="ex-feedback ok">Increment and decrement practice complete.</div>';
      if (window.__markStepComplete) window.__markStepComplete();
    }
    function render(){
      if (idx >= questions.length) return complete();
      const q = questions[idx];
      const progress = '<div class="ex-progress">Question ' + (idx + 1) + ' of ' + questions.length + ' - Score: ' + score + '</div>';
      if (q.type === 'mcq') {
        root.innerHTML = progress + '<div class="ex-prompt">' + q.q + '</div><div class="ex-options"></div><div class="ex-feedback"></div>';
        const opts = root.querySelector('.ex-options');
        q.options.forEach(opt => {
          const btn = document.createElement('button');
          btn.type = 'button';
          btn.className = 'ex-mcq-btn';
          btn.textContent = opt;
          btn.onclick = () => {
            const fb = root.querySelector('.ex-feedback');
            if (opt === q.answer) {
              score++;
              fb.className = 'ex-feedback ok';
              fb.textContent = q.right || 'Correct.';
              idx++;
              setTimeout(render, 800);
            } else {
              fb.className = 'ex-feedback err';
              fb.textContent = q.wrong || 'Not quite. Check the exact wording and symbols.';
            }
          };
          opts.appendChild(btn);
        });
        return;
      }
      const inputHtml = q.type === 'multiline'
        ? '<textarea class="ex-textarea" rows="6" spellcheck="false"></textarea>'
        : '<input class="ex-input" spellcheck="false" autocomplete="off">';
      root.innerHTML = progress + '<div class="ex-prompt">' + q.q + '</div>' + inputHtml + '<button type="button" class="ex-btn" style="margin-top:8px">Check</button><div class="ex-feedback"></div>';
      const input = root.querySelector(q.type === 'multiline' ? 'textarea' : 'input');
      const fb = root.querySelector('.ex-feedback');
      root.querySelector('button').onclick = () => {
        const ok = new RegExp(q.pattern, 'im').test(String(input.value || '').trim());
        if (ok) {
          score++;
          input.classList.add('correct');
          fb.className = 'ex-feedback ok';
          fb.textContent = q.right || 'Correct.';
          idx++;
          setTimeout(render, 800);
        } else {
          input.classList.add('wrong');
          fb.className = 'ex-feedback err';
          fb.textContent = q.wrong || 'Not quite. Check the exact condition, colon and indentation.';
          setTimeout(() => input.classList.remove('wrong'), 900);
        }
      };
      input.onkeydown = e => { if (e.key === 'Enter' && q.type !== 'multiline') root.querySelector('button').click(); };
      input.focus();
    }
    render();
  })();

