(() => {
    const root = document.getElementById("while-endless-box");
    if (!root) return;
    const bank = [{"type":"mcq","q":"Which line keeps running while total is less than 10?","options":["while total < 10:","while total <= 10:","while total < 10","while total > 10:"],"answer":"while total < 10:","right":"Correct.","wrong":"Use < and include the colon."},{"type":"text","q":"Write the first line for a loop that keeps running while lives is greater than 0.","pattern":"^\\s*while\\s+lives\\s*>\\s*0\\s*:\\s*$","right":"Correct.","wrong":"Use while lives > 0:"},{"type":"text","q":"Write the first line for a loop that keeps running while password is not equal to open.","pattern":"^\\s*while\\s+password\\s*!=\\s*['\"]open['\"]\\s*:\\s*$","right":"Correct.","wrong":"Use != and put open in quotes."},{"type":"text","q":"Write the first line for a loop that keeps running while count is less than or equal to 5.","pattern":"^\\s*while\\s+count\\s*<=\\s*5\\s*:\\s*$","right":"Correct.","wrong":"Use <=."},{"type":"mcq","q":"Which is a valid first line of a while loop?","options":["while speed > 30:","while speed > 30","whilst speed > 30:","while (speed > 30)"],"answer":"while speed > 30:","right":"Correct.","wrong":"Use while and a colon."},{"type":"text","q":"Write the first line for a loop that keeps running while temperature is less than 100.","pattern":"^\\s*while\\s+temperature\\s*<\\s*100\\s*:\\s*$","right":"Correct.","wrong":"Use while temperature < 100:"},{"type":"text","q":"Write the code that increases score by 5.","pattern":"^\\s*score\\s*\\+=\\s*5\\s*$","right":"Correct.","wrong":"Use score += 5."},{"type":"text","q":"Write the code that decreases lives by 1.","pattern":"^\\s*lives\\s*-=\\s*1\\s*$","right":"Correct.","wrong":"Use lives -= 1."},{"type":"text","q":"Write the code that increases total by 10.","pattern":"^\\s*total\\s*\\+=\\s*10\\s*$","right":"Correct.","wrong":"Use total += 10."},{"type":"text","q":"Write the code that decreases health by 25.","pattern":"^\\s*health\\s*-=\\s*25\\s*$","right":"Correct.","wrong":"Use health -= 25."},{"type":"mcq","q":"Which statement increases count by 1?","options":["count += 1","count -= 1","count =+ 1","count + 1"],"answer":"count += 1","right":"Correct.","wrong":"+= updates the variable."},{"type":"text","q":"Write the code that decreases battery by 5.","pattern":"^\\s*battery\\s*-=\\s*5\\s*$","right":"Correct.","wrong":"Use battery -= 5."},{"type":"multiline","q":"Write a loop that starts score at 0 and increases score by 1 until score reaches 5.","pattern":"^\\s*score\\s*=\\s*0\\s*[\\r\\n]+\\s*while\\s+score\\s*<\\s*5\\s*:\\s*[\\r\\n]+\\s+score\\s*\\+=\\s*1\\s*$","right":"Correct.","wrong":"Initialise score, test score < 5, then indent score += 1."},{"type":"multiline","q":"Write a loop that starts lives at 10 and decreases lives by 1 until lives reaches 0.","pattern":"^\\s*lives\\s*=\\s*10\\s*[\\r\\n]+\\s*while\\s+lives\\s*>\\s*0\\s*:\\s*[\\r\\n]+\\s+lives\\s*-=\\s*1\\s*$","right":"Correct.","wrong":"Initialise lives, test lives > 0, then indent lives -= 1."},{"type":"multiline","q":"Write a loop that starts total at 0 and adds 5 until total reaches 25.","pattern":"^\\s*total\\s*=\\s*0\\s*[\\r\\n]+\\s*while\\s+total\\s*<\\s*25\\s*:\\s*[\\r\\n]+\\s+total\\s*\\+=\\s*5\\s*$","right":"Correct.","wrong":"Use total += 5 inside the loop."},{"type":"mcq","q":"Why does a while loop usually need an update inside the loop?","options":["So the condition can eventually become False","So it becomes a for loop","So input stops working","So print uses quotes"],"answer":"So the condition can eventually become False","right":"Correct.","wrong":"Without an update, the loop may never stop."},{"type":"multiline","q":"Write a program that prints 0, 1, 2, 3, 4 using a while loop.","pattern":"^\\s*count\\s*=\\s*0\\s*[\\r\\n]+\\s*while\\s+count\\s*<\\s*5\\s*:\\s*[\\r\\n]+\\s+print\\s*\\(\\s*count\\s*\\)\\s*[\\r\\n]+\\s+count\\s*\\+=\\s*1\\s*$","right":"Correct.","wrong":"Print first, then update count."},{"type":"multiline","q":"Write a program that prints 3, 2, 1 using a while loop.","pattern":"^\\s*lives\\s*=\\s*3\\s*[\\r\\n]+\\s*while\\s+lives\\s*>\\s*0\\s*:\\s*[\\r\\n]+\\s+print\\s*\\(\\s*lives\\s*\\)\\s*[\\r\\n]+\\s+lives\\s*-=\\s*1\\s*$","right":"Correct.","wrong":"Print lives, then decrease it."},{"type":"multiline","q":"Write a program that prints 0, 2, 4, 6, 8 using a while loop.","pattern":"^\\s*count\\s*=\\s*0\\s*[\\r\\n]+\\s*while\\s+count\\s*<\\s*10\\s*:\\s*[\\r\\n]+\\s+print\\s*\\(\\s*count\\s*\\)\\s*[\\r\\n]+\\s+count\\s*\\+=\\s*2\\s*$","right":"Correct.","wrong":"Use count += 2."},{"type":"mcq","q":"Which code prints health first, then decreases it by 10?","options":["health = 50\nwhile health > 0:\n    print(health)\n    health -= 10","health = 50\nwhile health > 0:\n    health -= 10\n    print(health)","health = 0\nwhile health > 0:\n    print(health)\n    health -= 10","health = 50\nwhile health < 0:\n    print(health)\n    health -= 10"],"answer":"health = 50\nwhile health > 0:\n    print(health)\n    health -= 10","right":"Correct.","wrong":"The print line comes before the update line."}];
    let solved = 0;
    function pick(){ return bank[Math.floor(Math.random() * bank.length)]; }
    function finish(){
      root.innerHTML = '<div class="ex-feedback ok">Endless practice complete: 5 correct answers reached.</div>';
      if (window.__markStepComplete) window.__markStepComplete();
    }
    function render(){
      if (solved >= 5) return finish();
      const q = pick();
      const progress = '<div class="ex-progress">Endless target: 5 correct. Completed: ' + solved + '/5</div>';
      if (q.type === 'mcq') {
        root.innerHTML = progress + '<div class="ex-prompt">' + q.q + '</div><div class="ex-options"></div><div class="ex-feedback"></div>';
        const opts = root.querySelector('.ex-options');
        q.options.forEach(opt => {
          const btn = document.createElement('button');
          btn.type = 'button';
          btn.className = 'ex-mcq-btn';
          btn.textContent = opt;
          btn.onclick = () => {
            const fb = root.querySelector('.ex-feedback');
            if (opt === q.answer) { solved++; fb.className = 'ex-feedback ok'; fb.textContent = q.right || 'Correct.'; setTimeout(render, 700); }
            else { fb.className = 'ex-feedback err'; fb.textContent = q.wrong || 'Try the next one carefully.'; setTimeout(render, 1200); }
          };
          opts.appendChild(btn);
        });
        return;
      }
      const inputHtml = q.type === 'multiline'
        ? '<textarea class="ex-textarea" rows="6" spellcheck="false"></textarea>'
        : '<input class="ex-input" spellcheck="false" autocomplete="off">';
      root.innerHTML = progress + '<div class="ex-prompt">' + q.q + '</div>' + inputHtml + '<button type="button" class="ex-btn" style="margin-top:8px">Check</button><div class="ex-feedback"></div>';
      const input = root.querySelector(q.type === 'multiline' ? 'textarea' : 'input');
      const fb = root.querySelector('.ex-feedback');
      root.querySelector('button').onclick = () => {
        const ok = new RegExp(q.pattern, 'im').test(String(input.value || '').trim());
        if (ok) { solved++; fb.className = 'ex-feedback ok'; fb.textContent = q.right || 'Correct.'; setTimeout(render, 700); }
        else { fb.className = 'ex-feedback err'; fb.textContent = q.wrong || 'Try the next one carefully.'; setTimeout(render, 1200); }
      };
      input.focus();
    }
    render();
  })();

